import{_ as r,o as a,c as l,ae as o}from"./chunks/framework.DrYEjkpc.js";const u=JSON.parse('{"title":"SkillForge","description":"","frontmatter":{},"headers":[],"relativePath":"radar/tech-skillforge.md","filePath":"radar/tech-skillforge.md"}'),e={name:"radar/tech-skillforge.md"};function i(n,t,d,s,h,g){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="skillforge" tabindex="-1">SkillForge <a class="header-anchor" href="#skillforge" aria-label="Permalink to &quot;SkillForge&quot;">​</a></h1><blockquote><p><strong>分类</strong>: Skill 生成 / Skill 优化 / Skill 评测 | <strong>成熟度</strong>: 🟢 成熟期 | <strong>综合评分</strong>: 0.58</p></blockquote><hr><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><p><strong>一句话描述</strong>: <strong>工业研究</strong>的领域专属 Skill 自动化生产线 —— 从 <strong>1,883 条历史工单</strong>挖掘工具 schema + 三阶段自优化流水线，5 个真实云技术支持场景验证（<strong>SIGIR 2026 Industry Track</strong>）。</p><p><strong>来源</strong>:</p><ul><li>工业研究（SIGIR 2026 Industry Track）</li><li>注：论文摘要未明确署名 Alibaba Cloud，请以 PDF 正文为准</li></ul><p><strong>链接</strong>:</p><ul><li>论文：<a href="https://arxiv.org/abs/2604.08618" target="_blank" rel="noreferrer">arXiv 2604.08618</a></li></ul><hr><h2 id="核心技术" tabindex="-1">核心技术 <a class="header-anchor" href="#核心技术" aria-label="Permalink to &quot;核心技术&quot;">​</a></h2><h3 id="domain-contextualized-skill-creator" tabindex="-1">Domain-Contextualized Skill Creator <a class="header-anchor" href="#domain-contextualized-skill-creator" aria-label="Permalink to &quot;Domain-Contextualized Skill Creator&quot;">​</a></h3><p>从历史工单挖掘两类信息：</p><ol><li><strong>工具挖掘</strong> —— 识别专家在工单中高频使用的诊断工具，提取其 schema</li><li><strong>知识抽取</strong> —— 从内部文档和工单引用的参考资料中提取领域规则</li></ol><p><strong>例</strong>：分析 1000 个&quot;ECS 无法启动&quot;工单后发现：专家 90% 时间先跑 <code>ecs-diag</code> → 再查 VPC 安全组 → 最后看系统日志 —— 这个诊断路径被编码为 Skill。</p><h3 id="三阶段自优化流水线-关键创新" tabindex="-1">三阶段自优化流水线（关键创新） <a class="header-anchor" href="#三阶段自优化流水线-关键创新" aria-label="Permalink to &quot;三阶段自优化流水线（关键创新）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>角色</th></tr></thead><tbody><tr><td><strong>Failure Analyzer</strong></td><td>分析执行失败</td></tr><tr><td><strong>Skill Diagnostician</strong></td><td>将失败追溯到具体 Skill 缺陷（如&quot;Skill 没有告诉 Agent 在操作前检查实例状态&quot;）</td></tr><tr><td><strong>Skill Optimizer</strong></td><td>重写 Skill 消除根因</td></tr></tbody></table><p>关键在于<strong>直接将失败归因到 Skill</strong> —— 这是归因分离的初步方案。</p><h3 id="真实生产验证" tabindex="-1">真实生产验证 <a class="header-anchor" href="#真实生产验证" aria-label="Permalink to &quot;真实生产验证&quot;">​</a></h3><p>5 个真实云技术支持场景，使用 <strong>1,883 条匿名化生产工单 + 3,737 个任务</strong>。</p><hr><h2 id="技术细节" tabindex="-1">技术细节 <a class="header-anchor" href="#技术细节" aria-label="Permalink to &quot;技术细节&quot;">​</a></h2><h3 id="局限性" tabindex="-1">局限性 <a class="header-anchor" href="#局限性" aria-label="Permalink to &quot;局限性&quot;">​</a></h3><ul><li>仅在云技术支持场景验证，<strong>通用性未知</strong></li><li>代码和数据未开源（企业隐私）</li><li>聚焦<strong>单 Skill</strong> 优化，<strong>不涉及多 Skill 协同</strong></li><li>Diagnostician 只做&quot;是否 Skill 的问题&quot;这一层归因，不区分 Skill 内容 / 模型能力 / 路由错误</li></ul><hr><h2 id="成熟度评分" tabindex="-1">成熟度评分 <a class="header-anchor" href="#成熟度评分" aria-label="Permalink to &quot;成熟度评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>评分</th><th>说明</th></tr></thead><tbody><tr><td>技术成熟度</td><td>0.70</td><td>阿里云生产环境部署</td></tr><tr><td>创新性</td><td>0.65</td><td>三阶段流水线 + 归因分离思想新颖</td></tr><tr><td>落地程度</td><td>0.55</td><td>工业验证但未对外开放</td></tr><tr><td>生态活跃度</td><td>0.35</td><td>闭源，企业内部使用</td></tr></tbody></table><p><strong>综合评分</strong>: <strong>0.58</strong></p><hr><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2604.08618" target="_blank" rel="noreferrer">SkillForge 论文</a></li></ul>',31)])])}const k=r(e,[["render",i]]);export{u as __pageData,k as default};
